interface StatCardProps {
  icon: React.ComponentType<{ className?: string }>
  value: string
  label: string
  index: number
  visible: boolean
}

function StatCard({ icon: Icon, value, label, index, visible }: StatCardProps) {
  const { ref, count } = useCountUp(parseInt(value), 1500)

  return (
    <div
      ref={ref}
      className="group glass border-primary/30 rounded-xl p-5 md:p-6 text-center hover:border-accent/60 hover:shadow-lg hover:shadow-accent/20 transition-all duration-300 animate-fade-up"
      style={{ animationDelay: visible ? `${0.5 + index * 0.1}s` : "0s" }}
    >
      <Icon className="w-8 h-8 text-accent mx-auto mb-3 group-hover:text-primary transition-colors" />
      <div className="text-3xl md:text-4xl font-bold text-foreground">
        {count}
        {label === "Partners" || label === "Members" ? "+" : ""}
      </div>
      <div className="text-xs md:text-sm text-muted-foreground mt-2">{label}</div>
    </div>
  )
}
